      "solution": "import { Keypair } from '@solana/web3.js';\n\nfunction generateKeypair(): { publicKey: string; isValid: boolean } {\n  const keypair = Keypair.generate();\n  return {\n    publicKey: keypair.publicKey.toBase58(),\n    isValid: true,\n  };\n}",
